use distributed_inference::pleromatic_frame::PleromaticMediaType;
use distributed_inference::pleromatic_knot_storage::KnotStorage;
use std::env;

/// knot-recall: Search the Pleromatic archive for specific semantic residue.
///
/// Usage: knot-recall <query> [limit]
fn main() -> std::io::Result<()> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        eprintln!("Usage: knot-recall <query> [limit]");
        std::process::exit(1);
    }

    let query = args[1].to_lowercase();
    let limit = args
        .get(2)
        .and_then(|s| s.parse::<usize>().ok())
        .unwrap_or(5);

    let storage = KnotStorage::new("assets/memory");

    // Fetch up to the full 1000-frame quota
    let frames = storage.history(1000)?;

    let mut matches = Vec::new();

    for frame in frames {
        // Only search semantic frames for text matches
        if frame.media_type == PleromaticMediaType::Semantic {
            if let Ok(text) = String::from_utf8(frame.data.clone()) {
                if text.to_lowercase().contains(&query) {
                    matches.push(frame);
                }
            }
        }

        if matches.len() >= limit {
            break;
        }
    }

    let json = serde_json::to_string_pretty(&matches)
        .map_err(std::io::Error::other)?;
    println!("{}", json);

    Ok(())
}
